def group_anagrams(strs):
    groups = []
    for s in strs:
        placed = False
        for g in groups:
            if sorted(g[0]) == sorted(s):
                g.append(s)
                placed = True
                break
        if not placed:
            groups.append([s])
    groups = [sorted(g) for g in groups]
    groups.sort()
    return groups
